const std::size_t FLAT_PATTERNS_COUNT = 2159;

const std::vector<IdiomPattern>& get_patterns() {
    static const std::vector<IdiomPattern> patterns = [] {
        std::vector<IdiomPattern> result;
        result.reserve(FLAT_PATTERNS_COUNT);
        for (std::size_t i = 0; i < FLAT_PATTERNS_COUNT; ++i) {
            const auto& fp = FLAT_PATTERNS[i];
            IdiomPattern p;
            p.type = fp.type;
            p.cluster = fp.cluster;
            p.sequence.reserve(static_cast<std::size_t>(fp.sequence_len));
            for (int j = 0; j < fp.sequence_len; ++j) {
                PatternInstruction pi;
                pi.opcode = fp.sequence[j].opcode;
                for (std::size_t k = 0; k < MAX_PATTERN_OPERANDS; ++k) {
                    if (!fp.sequence[j].operands[k]) break;
                    pi.operands.emplace_back(fp.sequence[j].operands[k]);
                }
                p.sequence.push_back(std::move(pi));
            }
            result.push_back(std::move(p));
        }
        return result;
    }();
    return patterns;
}

